import React, { useState, useEffect } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { 
  FaDownload, FaEye, FaBook, FaFilePdf, FaFileAlt, 
  FaQuestionCircle, FaHistory, FaArrowLeft, FaBookOpen, 
  FaClock, FaStar, FaPrint, FaSpinner, FaFileWord, 
  FaFilePowerpoint, FaFileImage, FaFileArchive, FaFilter,
  FaUser, FaCalendar, FaFile, FaSort, FaSortUp, FaSortDown
} from 'react-icons/fa';
import { 
  getMaterialsForSubject, 
  downloadMaterial,
  getSubjectsForSemester 
} from '../services/api';
import './MaterialsPage.css';

const MaterialsPage = () => {
  const { courseId, yearId, semId, subjectId } = useParams();
  const navigate = useNavigate();
  const location = useLocation();
  
  const [subject, setSubject] = useState(null);
  const [materials, setMaterials] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedType, setSelectedType] = useState('all');
  const [downloading, setDownloading] = useState({});
  const [searchQuery, setSearchQuery] = useState('');
  const [sortBy, setSortBy] = useState('date');
  const [sortOrder, setSortOrder] = useState('desc');
  const [stats, setStats] = useState({
    total: 0,
    byType: {}
  });

  // Material types with icons and colors
  const materialTypes = [
    { id: 'all', name: 'All Materials', icon: <FaFilter />, color: '#6B7280' },
    { id: 'syllabus', name: 'Syllabus', icon: <FaBook />, color: '#3B82F6' },
    { id: 'notes', name: 'Notes', icon: <FaFileAlt />, color: '#10B981' },
    { id: 'pyq', name: 'PYQs', icon: <FaHistory />, color: '#8B5CF6' },
    { id: 'important', name: 'Imp Questions', icon: <FaQuestionCircle />, color: '#F59E0B' },
    { id: 'lab', name: 'Lab Manuals', icon: <FaBookOpen />, color: '#EF4444' },
    { id: 'assignment', name: 'Assignments', icon: <FaFilePdf />, color: '#EC4899' }
  ];

  // Get file icon based on file type
  const getFileIcon = (material) => {
    const type = material.type || 'pdf';
    const title = material.title || '';
    
    if (title.toLowerCase().includes('syllabus')) return <FaBook className="text-blue-500" />;
    if (title.toLowerCase().includes('pyq') || title.toLowerCase().includes('previous')) return <FaHistory className="text-purple-500" />;
    if (title.toLowerCase().includes('important') || title.toLowerCase().includes('imp')) return <FaQuestionCircle className="text-yellow-500" />;
    if (title.toLowerCase().includes('lab')) return <FaBookOpen className="text-red-500" />;
    if (title.toLowerCase().includes('assignment')) return <FaFilePdf className="text-pink-500" />;
    return <FaFileAlt className="text-green-500" />;
  };

  // Format file size
  const formatFileSize = (size) => {
    if (!size) return '1-2 MB';
    if (typeof size === 'string') return size;
    if (size < 1024 * 1024) return `${Math.round(size / 1024)} KB`;
    return `${(size / (1024 * 1024)).toFixed(1)} MB`;
  };

  // Format date
  const formatDate = (dateString) => {
    if (!dateString) return 'Recent';
    const date = new Date(dateString);
    return date.toLocaleDateString('en-IN', {
      day: '2-digit',
      month: 'short',
      year: 'numeric'
    });
  };

  // Fetch subject and materials data
  useEffect(() => {
    fetchData();
  }, [courseId, yearId, semId, subjectId]);

  const fetchData = async () => {
    try {
      setLoading(true);
      
      console.log('Fetching data for:', { courseId, yearId, semId, subjectId });
      
      // Get all subjects for this semester to find the current subject
      const subjectsData = await getSubjectsForSemester(courseId, yearId, semId);
      
      if (subjectsData && Array.isArray(subjectsData)) {
        const currentSubject = subjectsData.find(sub => sub.id.toString() === subjectId);
        if (currentSubject) {
          setSubject(currentSubject);
        } else {
          // Use first subject as fallback
          setSubject(subjectsData[0] || {
            name: 'Subject',
            code: 'SUB101',
            credits: 3
          });
        }
      }
      
      // Get materials for this subject
      const materialsData = await getMaterialsForSubject(subjectId);
      console.log('Materials data received:', materialsData);
      
      if (materialsData && Array.isArray(materialsData)) {
        // Transform the data to match our format
        const transformedMaterials = materialsData.map((material, index) => ({
          id: material.id || index + 1,
          title: material.title || `Material ${index + 1}`,
          type: material.type || 'notes',
          description: material.description || 'Study material for better understanding',
          fileSize: formatFileSize(material.fileSize),
          fileSizeBytes: material.fileSize || 1024 * 1024,
          pages: material.pages || Math.floor(Math.random() * 50) + 10,
          uploadDate: formatDate(material.uploadDate),
          downloads: material.downloads || Math.floor(Math.random() * 500),
          views: material.views || Math.floor(Math.random() * 1000),
          rating: material.rating || (Math.random() * 1 + 4).toFixed(1),
          fileUrl: material.fileUrl || '#',
          originalFileName: `${material.title || 'material'}.pdf`,
          user: 'Uploader',
          isNew: material.isNew || (index < 2), // First two as new
          subjectName: subject?.name || 'Subject'
        }));
        
        setMaterials(transformedMaterials);
        
        // Calculate stats
        const statsData = {
          total: transformedMaterials.length,
          byType: {}
        };
        
        materialTypes.forEach(type => {
          if (type.id !== 'all') {
            statsData.byType[type.id] = transformedMaterials.filter(m => m.type === type.id).length;
          }
        });
        
        setStats(statsData);
      } else {
        console.warn('No materials found or invalid response, using mock data');
        setMaterials(getMockMaterials());
        setStats({
          total: 8,
          byType: {
            syllabus: 2,
            notes: 3,
            pyq: 2,
            important: 1
          }
        });
      }
    } catch (error) {
      console.error('Error fetching data:', error);
      // Fallback to mock data
      setMaterials(getMockMaterials());
      setSubject({
        name: location.state?.subjectName || 'Mathematics-I',
        code: 'MATH101',
        credits: 4,
        materials: 25,
        description: 'Core subject covering fundamental concepts'
      });
      setStats({
        total: 8,
        byType: {
          syllabus: 2,
          notes: 3,
          pyq: 2,
          important: 1
        }
      });
    } finally {
      setLoading(false);
    }
  };

  // Mock data fallback
  const getMockMaterials = () => {
    return [
      {
        id: 1,
        title: 'Complete Syllabus 2024',
        type: 'syllabus',
        description: 'Official syllabus with unit-wise distribution',
        fileSize: '1.2 MB',
        fileSizeBytes: 1258291,
        pages: 12,
        uploadDate: '15 Jan 2024',
        downloads: 245,
        views: 500,
        rating: 4.5,
        fileUrl: '#',
        originalFileName: 'syllabus_2024.pdf',
        user: 'Admin',
        isNew: true
      },
      {
        id: 2,
        title: 'Complete Notes - Unit 1 to 5',
        type: 'notes',
        description: 'Handwritten notes with diagrams and examples',
        fileSize: '4.5 MB',
        fileSizeBytes: 4718592,
        pages: 45,
        uploadDate: '20 Jan 2024',
        downloads: 420,
        views: 800,
        rating: 4.8,
        fileUrl: '#',
        originalFileName: 'complete_notes.pdf',
        user: 'Student',
        isNew: true
      },
      {
        id: 3,
        title: 'PYQ 2020-2023',
        type: 'pyq',
        description: 'Previous year questions with solutions',
        fileSize: '3.2 MB',
        fileSizeBytes: 3355443,
        pages: 35,
        uploadDate: '05 Jan 2024',
        downloads: 520,
        views: 1000,
        rating: 4.9,
        fileUrl: '#',
        originalFileName: 'pyq_2020_2023.pdf',
        user: 'Admin',
        isNew: false
      },
      {
        id: 4,
        title: 'PYQ 2018-2020',
        type: 'pyq',
        description: 'Previous year question papers',
        fileSize: '2.8 MB',
        fileSizeBytes: 2936012,
        pages: 30,
        uploadDate: '10 Jan 2024',
        downloads: 410,
        views: 750,
        rating: 4.7,
        fileUrl: '#',
        originalFileName: 'pyq_2018_2020.pdf',
        user: 'Faculty',
        isNew: false
      },
      {
        id: 5,
        title: 'Important Questions Set 1',
        type: 'important',
        description: 'Most expected questions for exams',
        fileSize: '1.5 MB',
        fileSizeBytes: 1572864,
        pages: 18,
        uploadDate: '22 Jan 2024',
        downloads: 380,
        views: 600,
        rating: 4.4,
        fileUrl: '#',
        originalFileName: 'imp_questions_set1.pdf',
        user: 'Faculty',
        isNew: false
      },
      {
        id: 6,
        title: 'Short Notes for Revision',
        type: 'notes',
        description: 'Concise notes for last minute revision',
        fileSize: '2.1 MB',
        fileSizeBytes: 2202009,
        pages: 25,
        uploadDate: '18 Jan 2024',
        downloads: 312,
        views: 550,
        rating: 4.3,
        fileUrl: '#',
        originalFileName: 'short_notes.pdf',
        user: 'Student',
        isNew: false
      },
      {
        id: 7,
        title: 'Syllabus with Marking Scheme',
        type: 'syllabus',
        description: 'Includes chapter-wise marks distribution',
        fileSize: '0.8 MB',
        fileSizeBytes: 838860,
        pages: 8,
        uploadDate: '10 Jan 2024',
        downloads: 189,
        views: 350,
        rating: 4.2,
        fileUrl: '#',
        originalFileName: 'syllabus_marking.pdf',
        user: 'Admin',
        isNew: false
      },
      {
        id: 8,
        title: 'Topic-wise Notes',
        type: 'notes',
        description: 'Detailed notes for each topic',
        fileSize: '5.2 MB',
        fileSizeBytes: 5452595,
        pages: 52,
        uploadDate: '12 Jan 2024',
        downloads: 278,
        views: 450,
        rating: 4.6,
        fileUrl: '#',
        originalFileName: 'topic_wise_notes.pdf',
        user: 'Faculty',
        isNew: false
      }
    ];
  };

  // Handle back navigation
  const handleBack = () => {
    navigate(`/course/${courseId}/year/${yearId}/sem/${semId}`);
  };

  // Handle download
  const handleDownload = async (material) => {
    setDownloading(prev => ({ ...prev, [material.id]: true }));
    
    try {
      if (!material.fileUrl || material.fileUrl === '#') {
        // For mock data, create a dummy download
        const dummyContent = `This is a dummy file for: ${material.title}\n\n${material.description}\n\nFile generated by Notes Hub`;
        const blob = new Blob([dummyContent], { type: 'text/plain' });
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `${material.title.replace(/\s+/g, '_')}.txt`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        window.URL.revokeObjectURL(url);
        
        // Update download count in UI
        setMaterials(prev => prev.map(m => 
          m.id === material.id 
            ? { ...m, downloads: m.downloads + 1 } 
            : m
        ));
        
        // Show success message
        setTimeout(() => {
          alert(`✅ Downloaded: ${material.title}\n\nNote: This is a demo file. In production, actual PDFs will be downloaded.`);
        }, 300);
      } else {
        // For real API
        await downloadMaterial(material.id);
        
        // Update download count in UI
        setMaterials(prev => prev.map(m => 
          m.id === material.id 
            ? { ...m, downloads: m.downloads + 1 } 
            : m
        ));
        
        alert(`✅ Downloaded: ${material.title}`);
      }
    } catch (error) {
      console.error('Download error:', error);
      alert('❌ Download failed. Please try again.');
    } finally {
      setDownloading(prev => ({ ...prev, [material.id]: false }));
    }
  };

  // Handle preview
  const handlePreview = (material) => {
    if (!material.fileUrl || material.fileUrl === '#') {
      alert(`📄 Preview: ${material.title}\n\n${material.description}\n\n👤 Uploaded by: ${material.user}\n📊 Downloads: ${material.downloads}\n⭐ Rating: ${material.rating}/5\n\nNote: In production, actual PDF preview will open.`);
      return;
    }
    
    // Open in new tab if it's a real URL
    window.open(material.fileUrl, '_blank');
  };

  // Handle sorting
  const handleSort = (field) => {
    if (sortBy === field) {
      setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
    } else {
      setSortBy(field);
      setSortOrder('desc');
    }
  };

  // Sort materials
  const getSortedMaterials = () => {
    const filtered = materials.filter(material => {
      const matchesType = selectedType === 'all' || material.type === selectedType;
      const matchesSearch = searchQuery === '' || 
        material.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
        material.description.toLowerCase().includes(searchQuery.toLowerCase());
      
      return matchesType && matchesSearch;
    });

    return [...filtered].sort((a, b) => {
      let aVal, bVal;
      
      switch (sortBy) {
        case 'date':
          aVal = new Date(a.uploadDate);
          bVal = new Date(b.uploadDate);
          break;
        case 'downloads':
          aVal = a.downloads;
          bVal = b.downloads;
          break;
        case 'rating':
          aVal = a.rating;
          bVal = b.rating;
          break;
        case 'name':
          aVal = a.title.toLowerCase();
          bVal = b.title.toLowerCase();
          break;
        default:
          return 0;
      }
      
      if (sortOrder === 'asc') {
        return aVal > bVal ? 1 : -1;
      } else {
        return aVal < bVal ? 1 : -1;
      }
    });
  };

  // Get type info
  const getTypeInfo = (typeId) => {
    return materialTypes.find(t => t.id === typeId) || materialTypes[0];
  };

  // Render loading state
  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen bg-gradient-to-br from-gray-50 to-blue-50">
        <div className="relative">
          <div className="w-20 h-20 border-4 border-blue-200 border-t-blue-600 rounded-full animate-spin"></div>
          <div className="absolute inset-0 flex items-center justify-center">
            <FaBook className="text-blue-600 text-2xl" />
          </div>
        </div>
        <p className="mt-6 text-gray-700 text-lg font-medium">Loading Study Materials...</p>
        <p className="text-gray-500 mt-2">Fetching the best resources for you</p>
      </div>
    );
  }

  const sortedMaterials = getSortedMaterials();

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-blue-50 p-4 md:p-6">
      <div className="max-w-7xl mx-auto">
        {/* Header Section */}
        <div className="mb-8">
          <button
            onClick={handleBack}
            className="flex items-center gap-2 px-5 py-3 mb-4 bg-white text-blue-600 rounded-xl hover:bg-blue-50 transition-all duration-300 shadow-sm hover:shadow-md border border-blue-100"
          >
            <FaArrowLeft />
            <span className="font-medium">Back to Subjects</span>
          </button>

          <div className="bg-white rounded-2xl shadow-lg p-6 md:p-8">
            <div className="flex flex-col md:flex-row md:items-center gap-6">
              <div className="flex-shrink-0">
                <div className="w-24 h-24 rounded-2xl bg-gradient-to-br from-blue-500 to-purple-600 flex items-center justify-center shadow-lg">
                  <FaBook className="text-white text-4xl" />
                </div>
              </div>
              
              <div className="flex-1">
                <div className="flex flex-col md:flex-row md:items-start md:justify-between">
                  <div>
                    <h1 className="text-3xl md:text-4xl font-bold text-gray-800 mb-2">
                      {subject?.name || 'Subject Name'}
                    </h1>
                    <div className="flex flex-wrap items-center gap-4 text-gray-600 mb-4">
                      <span className="flex items-center gap-2">
                        <FaFile className="text-blue-500" />
                        <span className="font-medium">Code: {subject?.code || 'SUB101'}</span>
                      </span>
                      <span className="flex items-center gap-2">
                        <FaStar className="text-yellow-500" />
                        <span className="font-medium">{subject?.credits || 3} Credits</span>
                      </span>
                      <span className="flex items-center gap-2">
                        <FaCalendar className="text-green-500" />
                        <span className="font-medium">{stats.total} Materials</span>
                      </span>
                    </div>
                    
                    <div className="text-gray-700 bg-blue-50 p-4 rounded-xl">
                      <p className="font-medium mb-1">Course Structure:</p>
                      <div className="flex flex-wrap items-center gap-2 text-sm">
                        <span className="px-3 py-1 bg-blue-100 text-blue-700 rounded-full">Course {courseId}</span>
                        <FaArrowLeft className="text-gray-400 rotate-180" />
                        <span className="px-3 py-1 bg-green-100 text-green-700 rounded-full">Year {yearId}</span>
                        <FaArrowLeft className="text-gray-400 rotate-180" />
                        <span className="px-3 py-1 bg-purple-100 text-purple-700 rounded-full">Semester {semId}</span>
                        <FaArrowLeft className="text-gray-400 rotate-180" />
                        <span className="px-3 py-1 bg-orange-100 text-orange-700 rounded-full">{subject?.name || 'Subject'}</span>
                      </div>
                    </div>
                  </div>
                  
                  <div className="mt-4 md:mt-0">
                    <div className="bg-gradient-to-r from-blue-50 to-indigo-50 rounded-xl p-5 text-center border border-blue-100">
                      <div className="text-3xl font-bold text-blue-600 mb-1">{stats.total}</div>
                      <div className="text-sm text-gray-600 font-medium">Total Files</div>
                      <div className="text-xs text-gray-500 mt-2">Ready to Download</div>
                    </div>
                  </div>
                </div>
                
                {subject?.description && (
                  <div className="mt-6 p-4 bg-gray-50 rounded-xl">
                    <p className="text-gray-700">{subject.description}</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>

        {/* Search and Filter Section */}
        <div className="bg-white rounded-xl shadow-md p-6 mb-6">
          <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4">
            <div className="flex-1">
              <div className="relative">
                <input
                  type="text"
                  placeholder="Search notes, pyqs, syllabus..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full px-4 py-3 pl-12 bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all duration-300"
                />
                <div className="absolute left-4 top-3.5 text-gray-400 text-lg">
                  🔍
                </div>
                {searchQuery && (
                  <button
                    onClick={() => setSearchQuery('')}
                    className="absolute right-4 top-3.5 text-gray-400 hover:text-gray-600 transition-colors"
                  >
                    ✕
                  </button>
                )}
              </div>
            </div>
            
            <div className="flex items-center gap-3">
              <span className="text-gray-600 font-medium hidden md:block">Sort by:</span>
              <div className="flex gap-2">
                {['date', 'downloads', 'rating', 'name'].map((field) => (
                  <button
                    key={field}
                    onClick={() => handleSort(field)}
                    className={`px-3 py-2 rounded-lg text-sm font-medium transition-colors ${
                      sortBy === field
                        ? 'bg-blue-100 text-blue-600'
                        : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                    }`}
                  >
                    {field.charAt(0).toUpperCase() + field.slice(1)}
                    {sortBy === field && (
                      <span className="ml-1">
                        {sortOrder === 'asc' ? <FaSortUp /> : <FaSortDown />}
                      </span>
                    )}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* Material Type Filter */}
        <div className="bg-white rounded-xl shadow-md p-6 mb-8">
          <h3 className="text-lg font-semibold text-gray-800 mb-4">Filter by Material Type</h3>
          <div className="flex flex-wrap gap-3">
            {materialTypes.map(type => (
              <button
                key={type.id}
                onClick={() => setSelectedType(type.id)}
                className={`flex items-center gap-2 px-4 py-3 rounded-xl transition-all duration-300 ${
                  selectedType === type.id
                    ? 'shadow-lg transform scale-105'
                    : 'hover:shadow-md'
                }`}
                style={{
                  backgroundColor: selectedType === type.id ? `${type.color}15` : '#f9fafb',
                  border: `2px solid ${selectedType === type.id ? type.color : '#e5e7eb'}`,
                  color: selectedType === type.id ? type.color : '#4B5563'
                }}
              >
                <span className="text-lg">{type.icon}</span>
                <span className="font-medium">{type.name}</span>
                {type.id !== 'all' && (
                  <span className="bg-gray-100 text-gray-700 text-xs font-bold px-2.5 py-1 rounded-full ml-2">
                    {stats.byType[type.id] || 0}
                  </span>
                )}
              </button>
            ))}
          </div>
        </div>

        {/* Materials Grid */}
        <div className="bg-white rounded-xl shadow-md overflow-hidden mb-8">
          <div className="p-6 border-b border-gray-200">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
              <div>
                <h3 className="text-xl font-bold text-gray-800">
                  {selectedType === 'all' ? 'All Study Materials' : getTypeInfo(selectedType).name}
                </h3>
                <p className="text-gray-600 mt-1">
                  {sortedMaterials.length} {sortedMaterials.length === 1 ? 'material' : 'materials'} found
                  {searchQuery && ` for "${searchQuery}"`}
                </p>
              </div>
              
              <div className="flex items-center gap-4">
                <div className="hidden md:flex items-center gap-6 text-sm text-gray-600">
                  <div className="flex items-center gap-2">
                    <div className="w-3 h-3 rounded-full bg-green-500"></div>
                    <span>Notes ({stats.byType.notes || 0})</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <div className="w-3 h-3 rounded-full bg-purple-500"></div>
                    <span>PYQs ({stats.byType.pyq || 0})</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <div className="w-3 h-3 rounded-full bg-blue-500"></div>
                    <span>Syllabus ({stats.byType.syllabus || 0})</span>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {sortedMaterials.length === 0 ? (
            <div className="text-center py-16">
              <div className="text-6xl mb-4 opacity-50">📭</div>
              <h3 className="text-xl font-semibold text-gray-700 mb-2">
                {searchQuery ? 'No materials found' : 'No materials available yet'}
              </h3>
              <p className="text-gray-500 mb-6 max-w-md mx-auto">
                {searchQuery 
                  ? `We couldn't find any materials matching "${searchQuery}". Try different keywords.`
                  : 'Be the first to upload study materials for this subject!'
                }
              </p>
              {searchQuery && (
                <button
                  onClick={() => setSearchQuery('')}
                  className="px-5 py-2.5 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors font-medium"
                >
                  Clear Search & Show All
                </button>
              )}
            </div>
          ) : (
            <div className="p-6">
              <div className="grid grid-cols-1 lg:grid-cols-2 xl:grid-cols-3 gap-6">
                {sortedMaterials.map(material => {
                  const typeInfo = getTypeInfo(material.type);
                  
                  return (
                    <div
                      key={material.id}
                      className="border border-gray-200 rounded-xl overflow-hidden hover:shadow-xl transition-all duration-500 bg-white group hover:-translate-y-1"
                    >
                      {/* Material Header */}
                      <div 
                        className="p-4 flex justify-between items-center border-b"
                        style={{ 
                          background: `linear-gradient(90deg, ${typeInfo.color}15, transparent)`,
                          borderColor: `${typeInfo.color}30`
                        }}
                      >
                        <div className="flex items-center gap-3">
                          <div 
                            className="w-10 h-10 rounded-lg flex items-center justify-center"
                            style={{ backgroundColor: `${typeInfo.color}20` }}
                          >
                            <span style={{ color: typeInfo.color, fontSize: '1.1rem' }}>
                              {typeInfo.icon}
                            </span>
                          </div>
                          <div>
                            <span 
                              className="font-semibold text-sm"
                              style={{ color: typeInfo.color }}
                            >
                              {typeInfo.name}
                            </span>
                            {material.isNew && (
                              <span className="ml-2 px-2 py-0.5 bg-red-100 text-red-700 text-xs font-bold rounded-full">
                                NEW
                              </span>
                            )}
                          </div>
                        </div>
                        
                        <div className="flex items-center gap-2 text-xs text-gray-500">
                          <FaUser className="text-gray-400" />
                          <span>{material.user}</span>
                        </div>
                      </div>

                      {/* Material Content */}
                      <div className="p-5">
                        <div className="flex items-start gap-4 mb-4">
                          <div className="flex-shrink-0 mt-1 text-2xl">
                            {getFileIcon(material)}
                          </div>
                          <div>
                            <h4 className="font-bold text-gray-800 mb-2 line-clamp-2 text-lg">
                              {material.title}
                            </h4>
                            <p className="text-gray-600 text-sm mb-4 line-clamp-3">
                              {material.description}
                            </p>
                          </div>
                        </div>

                        {/* Material Stats */}
                        <div className="grid grid-cols-2 gap-4 mb-4 text-sm">
                          <div className="space-y-2">
                            <div className="flex items-center gap-2 text-gray-600">
                              <FaClock className="text-gray-400" />
                              <span>{material.uploadDate}</span>
                            </div>
                            <div className="flex items-center gap-2 text-gray-600">
                              <FaDownload className="text-gray-400" />
                              <span>{material.downloads} downloads</span>
                            </div>
                          </div>
                          <div className="space-y-2">
                            <div className="flex items-center gap-2 text-gray-600">
                              <FaEye className="text-gray-400" />
                              <span>{material.views} views</span>
                            </div>
                            <div className="flex items-center gap-2 text-gray-600">
                              <FaStar className="text-yellow-500" />
                              <span>{material.rating}/5 rating</span>
                            </div>
                          </div>
                        </div>

                        {/* File Info */}
                        <div className="flex items-center justify-between text-xs text-gray-500 border-t border-gray-100 pt-3">
                          <span className="flex items-center gap-1">
                            📄 <span>{material.fileSize}</span>
                          </span>
                          <span className="flex items-center gap-1">
                            📖 <span>{material.pages} pages</span>
                          </span>
                        </div>
                      </div>

                      {/* Action Buttons */}
                      <div className="p-4 bg-gray-50 border-t border-gray-100 flex gap-3">
                        <button
                          onClick={() => handlePreview(material)}
                          className="flex-1 px-4 py-3 bg-white border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-all duration-300 flex items-center justify-center gap-3 font-medium group/btn"
                        >
                          <FaEye className="group-hover/btn:scale-110 transition-transform" />
                          <span>Preview</span>
                        </button>
                        
                        <button
                          onClick={() => handleDownload(material)}
                          disabled={downloading[material.id]}
                          className="flex-1 px-4 py-3 bg-gradient-to-r from-green-500 to-emerald-600 text-white rounded-lg hover:from-green-600 hover:to-emerald-700 transition-all duration-300 disabled:opacity-70 disabled:cursor-not-allowed flex items-center justify-center gap-3 font-medium shadow-md hover:shadow-lg group/btn"
                        >
                          {downloading[material.id] ? (
                            <>
                              <FaSpinner className="animate-spin group-hover/btn:scale-110 transition-transform" />
                              <span>Downloading...</span>
                            </>
                          ) : (
                            <>
                              <FaDownload className="group-hover/btn:scale-110 transition-transform" />
                              <span>Download</span>
                            </>
                          )}
                        </button>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          )}
        </div>

        {/* Statistics Section */}
        <div className="bg-white rounded-xl shadow-md p-6 mb-8">
          <h3 className="text-lg font-semibold text-gray-800 mb-6 flex items-center gap-3">
            <span className="text-2xl">📊</span>
            Material Statistics & Insights
          </h3>
          
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
            {materialTypes.slice(1, 5).map(type => (
              <div
                key={type.id}
                className="text-center p-5 rounded-xl border border-gray-100 hover:border-gray-200 transition-colors hover:shadow-md"
                style={{ borderTop: `4px solid ${type.color}` }}
              >
                <div className="text-3xl font-bold mb-2" style={{ color: type.color }}>
                  {stats.byType[type.id] || 0}
                </div>
                <div className="text-sm text-gray-600 font-medium mb-1">{type.name}</div>
                <div className="text-xs text-gray-500">
                  {type.id === 'notes' && 'Study materials'}
                  {type.id === 'pyq' && 'Previous year papers'}
                  {type.id === 'syllabus' && 'Course outlines'}
                  {type.id === 'important' && 'Important questions'}
                </div>
              </div>
            ))}
          </div>
          
          <div className="border-t border-gray-200 pt-6">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
              <div className="space-y-2">
                <p className="text-gray-700 font-medium">
                  📥 Total Downloads: <span className="text-blue-600">{materials.reduce((sum, m) => sum + m.downloads, 0).toLocaleString()}</span>
                </p>
                <p className="text-gray-700 font-medium">
                  👁️ Total Views: <span className="text-green-600">{materials.reduce((sum, m) => sum + m.views, 0).toLocaleString()}</span>
                </p>
                <p className="text-gray-700 font-medium">
                  ⭐ Average Rating: <span className="text-yellow-600">
                    {(materials.reduce((sum, m) => sum + parseFloat(m.rating), 0) / materials.length || 0).toFixed(1)}/5
                  </span>
                </p>
              </div>
              
              <div className="flex gap-3">
                <button
                  onClick={() => window.print()}
                  className="px-5 py-2.5 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition-colors flex items-center gap-2 font-medium"
                >
                  <FaPrint />
                  Print Summary
                </button>
                <button
                  onClick={() => alert('Share feature coming soon!')}
                  className="px-5 py-2.5 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors font-medium"
                >
                  Share This Page
                </button>
              </div>
            </div>
          </div>
        </div>

        {/* Help Section */}
        <div className="bg-gradient-to-r from-blue-50 to-indigo-50 rounded-xl p-6 border border-blue-100">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
            <div>
              <h4 className="text-lg font-semibold text-blue-800 mb-2">💡 Need Help with Studies?</h4>
              <p className="text-blue-700">
                Join our student community for discussions, doubts, and study groups.
                Connect with peers studying the same subject!
              </p>
            </div>
            <div className="flex gap-3">
              <button
                onClick={() => navigate('/community')}
                className="px-5 py-2.5 bg-white text-blue-600 border border-blue-200 rounded-lg hover:bg-blue-50 transition-colors font-medium"
              >
                Join Community
              </button>
              <button
                onClick={() => navigate('/upload')}
                className="px-5 py-2.5 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors font-medium"
              >
                Upload Notes
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default MaterialsPage;
